select 
from biz_profit_unit
where owner_name = #{ownerName}
  and start_date = #{startDate}
  and transfer_date = #{transferDate}
  and profit_unit_name = #{profitUnitName}
  and deal_type = #{dealType}
limit 1

select from biz_profit_unit where trim(owner_name) = trim(#{ownerName}) and trim(profit_unit_name) = trim(#{profitUnitName}) and ifnull(trim(deal_type), '') = ifnull(trim(#{dealType}), '') and start_date is not null and transfer_date is not null and start_date <= #{transferDate} and transfer_date >= #{startDate}
and id != #{excludeId}
order by start_date asc, id asc limit 1

select 
from biz_profit_unit


        and profit_unit_name like concat('%', #{profitUnitName}, '%')


        and platform = #{platform}


        and brand_name = #{brandName}


        and dept_name = #{deptName}


        and owner_name = #{ownerName}


        and deal_type = #{dealType}


        and status = #{status}


order by id desc

